window.onload = init;
let check = false;
// Get the ball element

let theBall;

function init() {

    theBall = document.getElementById('ball')


    // Optional: attach click event
    theBall.addEventListener("click", kick_ball);

}


// Kick ball
function kick_ball() {
    // theBall.classList.add("animate");
    if (!check) {
        theBall.classList.add("animate");
        check =!check;
    }
    console.log(check)

}